     1→import type { StateCreator } from 'zustand';
     2→import {
     3→  PointsExtractStatus,
     4→  PointsBalanceStatus,
     5→  type PointsExtractState,
     6→  type PointsBalanceState,
     7→  type PointsExtractFiltersState,
     8→  type PointsExtractData,
     9→  type ProcessedExtractData,
    10→  type AppliedFilters,
    11→} from '../models';
    12→
    13→export interface PointsExtractActions {
    14→  setExtractStatus: (status: PointsExtractStatus) => void;
    15→  setExtractData: (extractData: PointsExtractData, processedExtractData?: ProcessedExtractData) => void;
    16→  appendExtractData: (extractData: PointsExtractData, processedExtractData?: ProcessedExtractData) => void;
    17→  setLoadingMore: (isLoading: boolean) => void;
    18→  setBalanceStatus: (status: PointsBalanceStatus) => void;
    19→  setBalance: (points?: number) => void;
    20→  setTransactionsFilters: (filters: AppliedFilters) => void;
    21→  clearTransactionsFilters: () => void;
    22→  reset: () => void;
    23→}
    24→
    25→export interface PointsExtractSlice {
    26→  pointsExtract: PointsExtractState;
    27→  pointsBalance: PointsBalanceState;
    28→  pointsExtractFilters: PointsExtractFiltersState;
    29→  pointsExtractActions: PointsExtractActions;
    30→}
    31→
    32→const INITIAL_POINTS_EXTRACT_STATE: PointsExtractState = {
    33→  extractData: undefined,
    34→  processedExtractData: undefined,
    35→  status: PointsExtractStatus.IDLE,
    36→  isLoadingMore: false,
    37→  error: undefined,
    38→};
    39→
    40→const INITIAL_POINTS_BALANCE_STATE: PointsBalanceState = {
    41→  points: undefined,
    42→  status: PointsBalanceStatus.IDLE,
    43→  error: undefined,
    44→};
    45→
    46→const INITIAL_POINTS_EXTRACT_FILTERS_STATE: PointsExtractFiltersState = {
    47→  appliedTransactionsFilters: undefined,
    48→};
    49→
    50→export const createPointsExtractSlice: StateCreator<
    51→  PointsExtractSlice,
    52→  [],
    53→  [],
    54→  PointsExtractSlice
    55→> = (set) => ({
    56→  pointsExtract: INITIAL_POINTS_EXTRACT_STATE,
    57→  pointsBalance: INITIAL_POINTS_BALANCE_STATE,
    58→  pointsExtractFilters: INITIAL_POINTS_EXTRACT_FILTERS_STATE,
    59→  pointsExtractActions: {
    60→    setExtractStatus: (status) =>
    61→      set((state) => ({
    62→        pointsExtract: { 
    63→          ...state.pointsExtract, 
    64→          status,
    65→          ...(status === PointsExtractStatus.IDLE || status === PointsExtractStatus.LOADING ? { error: undefined } : {}),
    66→        },
    67→      })),
    68→    setExtractData: (extractData, processedExtractData) =>
    69→      set((state) => ({
    70→        pointsExtract: {
    71→          ...state.pointsExtract,
    72→          extractData,
    73→          processedExtractData,
    74→          status: PointsExtractStatus.SUCCESS,
    75→          isLoadingMore: false,
    76→          error: undefined,
    77→        },
    78→      })),
    79→    appendExtractData: (extractData, processedExtractData) =>
    80→      set((state) => {
    81→        const existingTransactions = state.pointsExtract.extractData?.transactions ?? [];
    82→        const newTransactions = extractData.transactions;
    83→        const mergedTransactions = [...existingTransactions, ...newTransactions];
    84→
    85→        const existingProcessed = state.pointsExtract.processedExtractData;
    86→        const newProcessed = processedExtractData;
    87→
    88→        let mergedProcessed: ProcessedExtractData | undefined;
    89→        if (existingProcessed && newProcessed) {
    90→          const existingMapped = existingProcessed.mappedTransactions ?? [];
    91→          const newMapped = newProcessed.mappedTransactions ?? [];
    92→          mergedProcessed = {
    93→            groupedTransactions: newProcessed.groupedTransactions,
    94→            mappedTransactions: [...existingMapped, ...newMapped],
    95→          };
    96→        } else {
    97→          mergedProcessed = newProcessed ?? existingProcessed;
    98→        }
    99→
   100→        return {
   101→          pointsExtract: {
   102→            ...state.pointsExtract,
   103→            extractData: {
   104→              transactions: mergedTransactions,
   105→              pagination: extractData.pagination,
   106→            },
   107→            processedExtractData: mergedProcessed,
   108→            isLoadingMore: false,
   109→          },
   110→        };
   111→      }),
   112→    setLoadingMore: (isLoading) =>
   113→      set((state) => ({
   114→        pointsExtract: { ...state.pointsExtract, isLoadingMore: isLoading },
   115→      })),
   116→    setBalanceStatus: (status) =>
   117→      set((state) => ({
   118→        pointsBalance: { ...state.pointsBalance, status },
   119→      })),
   120→    setBalance: (points) =>
   121→      set((state) => ({
   122→        pointsBalance: {
   123→          ...state.pointsBalance,
   124→          points,
