     1→import { postRescueApi } from '../api';
     2→import { useRootStore } from '~/store';
     3→import { RescueStatus, RescuePayload } from '../models';
     4→import { getParticipantIdFromToken } from '../utils';
     5→
     6→export async function postRescue(payload: RescuePayload): Promise<boolean> {
     7→  const { rescueActions } = useRootStore.getState();
     8→
     9→  try {
    10→    rescueActions.setStatus(RescueStatus.LOADING);
    11→
    12→    const participantId = payload.participantId ?? (await getParticipantIdFromToken());
    13→
    14→    const finalPayload: RescuePayload = {
    15→      ...payload,
    16→      ...(participantId ? { participantId } : {}),
    17→    };
    18→
    19→    const response = await postRescueApi(finalPayload);
    20→
    21→    const rawStatus = response?.data?.status ?? response?.data?.data?.status;
    22→
    23→    if (!rawStatus) {
    24→      rescueActions.setError('No status in response');
    25→      return false;
    26→    }
    27→
    28→    const isSuccess = rawStatus?.message?.toLowerCase() === 'success';
    29→
    30→    if (isSuccess) {
    31→      rescueActions.setSuccess(rawStatus);
    32→      return true;
    33→    }
    34→
    35→    rescueActions.setError(rawStatus?.message || 'Rescue failed');
    36→    return false;
    37→  } catch {
    38→    rescueActions.setError('Rescue request failed');
    39→    return false;
    40→  }
